      expect(result.results[0].premium).toBe(60);
    });
    it("applies block discount for exactly 3 alike components (3 runes = 60 + 6 + 5 = 71 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
